FROM jsonb_array_elements('[{"id":"hampworth-sp5","name":"Hampworth","village":"Hampworth","town":"Salisbury","county":"Wiltshire","postcode":"SP5","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.01576,"lng":-1.85488},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"high-cross-gu32","name":"High Cross","village":"High Cross","town":"Petersfield","county":"Hampshire","postcode":"GU32","hubCity":"Guildford","regionDir":"","settlementType":"","subRegion":"Petersfield","coords":{"lat":50.99292,"lng":-0.93676},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"A small village in the civil parish of Froxfield and Privett, East Hampshire district, about three miles north-west of Petersfield and just north of the A272. High Cross is functionally the service hub of the parish: it holds Froxfield Church of England Primary and Pre-School, the King George V Memorial (Froxfield) Village Hall, St Peter''s Church (built 1862, with three Norman arches reconstructed from the older church at Froxfield Green) and the Trooper Inn — a 17th-century pub with rooms that markets itself as occupying the highest point in Hampshire. The wider parish has a population of around 929 (2021 census) and includes the linked settlements of Froxfield Green, Privett and Stroud Common. Together they sit on the edge of the hangers landscape inside the South Downs National Park.","character":"Linear downland village strung along the High Cross Lane and Alton Road; mix of period brick-and-flint cottages, post-war detached and a few newer infill dwellings. Active parish life — village hall events, Froxfield Choir, primary school — with a strong commuter and downsizer demographic.","amenities":["Froxfield CofE Primary and Pre-School","King George V Memorial (Froxfield) Village Hall","St Peter''s Church, High Cross (1862, Grade II listed)","The Trooper Inn (pub with eight rooms)","Footpaths onto the Hangers and Ashford Hangers Nature Reserve","Active Froxfield Choir"],"schools":[{"name":"Froxfield Church of England Primary and Pre-School","phase":"Primary (2–11)","ofsted":"Good (March 2024)","distance":"in village","url":"https://reports.ofsted.gov.uk/provider/21/116289"},{"name":"The Petersfield School","phase":"Secondary","ofsted":"Good","distance":"3.5 mi","url":"https://www.tps.hants.sch.uk/"},{"name":"Churcher''s College","phase":"Independent (3–18)","ofsted":null,"distance":"3.5 mi","url":"https://www.churcherscollege.com/"}],"transport":{"commutes":[{"to":"London Waterloo","time":"1h 2m – 1h 17m direct","mode":"drive to Petersfield + direct South Western Railway","source":"https://www.southwesternrailway.com/train-times/petersfield-to-london-waterloo"},{"to":"Portsmouth Harbour","time":"~30m","mode":"drive to Petersfield + direct South Western Railway","source":"https://www.southwesternrailway.com/travelling-with-us/at-the-station/petersfield"}],"nearestStation":"Petersfield (2.7 mi)","roads":"A272 (Petersfield–Winchester) at the southern edge; A3 (London–Portsmouth) ~3 mi east at Petersfield"},"prices":{"avgSold12Mo":null,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/gu32-1eg.html","asOf":"2026-05"},"thingsToDo":["Hangers Way long-distance trail","Walks in Ashford Hangers National Nature Reserve","Shoulder of Mutton Hill (Edward Thomas memorial)","Selborne (Gilbert White''s House, ~5 mi)","Jane Austen''s House at Chawton (~10 mi)"],"placesToEat":[{"name":"The Trooper Inn","type":"Pub with rooms and restaurant","notes":"17th-century inn on Alton Road at High Cross with eight en-suite rooms and an open-fire bar","url":"https://www.trooperinn.com/"},{"name":"The Pub With No Name (White Horse)","type":"Country pub","notes":"Famously unsigned 17th-century pub at Priors Dean, ~3 mi north-east","url":"https://www.pubwithnoname.co.uk/"}],"pros":["Village primary school (Froxfield CofE, Good 2024) and a working pub in the village","Inside the South Downs National Park","Petersfield station within 3 miles for direct London Waterloo trains","Strong cluster of independent schools nearby (Churcher''s, Bedales)","Hangers Way, Ashford Hangers and Selborne all within an easy walk or drive"],"cons":["No village shop; shops are in Petersfield or East Meon","Houses on the A272 / Alton Road have road noise","Tight planning regime (SDNP + village settlement boundary) limits new build","No through-bus service to count on at evenings/weekends","Petersfield ''rush hour'' through Sheet and the A3 junction can be slow"],"whoItSuits":"Families targeting Froxfield CofE Primary and the Petersfield/Churcher''s secondary catchment, who want a working village with a pub and hall on foot rather than an isolated hamlet. Also suits commuters comfortable with a 5-minute drive to Petersfield station for the Portsmouth Direct line. Less suited to buyers needing a village shop or supermarket on foot, or those wanting to be in walking distance of a railway station.","broadbandMedianMbps":null,"nearestStation":"Petersfield (2.7 mi)","primarySupermarket":"Waitrose Petersfield, Lavant Street (~3 mi); Tesco Petersfield, Bedford Road (~3.5 mi)","images":[],"sources":[{"label":"Wikipedia — High Cross, Hampshire","url":"https://en.wikipedia.org/wiki/High_Cross,_Hampshire"},{"label":"Wikipedia — Froxfield and Privett parish","url":"https://en.wikipedia.org/wiki/Froxfield_and_Privett"},{"label":"Ofsted — Froxfield CofE Primary","url":"https://reports.ofsted.gov.uk/provider/21/116289"},{"label":"The Trooper Inn","url":"https://www.trooperinn.com/"},{"label":"Froxfield Village Hall (King George V Memorial)","url":"https://www.froxfieldvillagehall.co.uk/"},{"label":"South Western Railway — Petersfield","url":"https://www.southwesternrailway.com/train-times/petersfield-to-london-waterloo"},{"label":"East Hants DC — Council Tax 2026/27 (Froxfield & Privett)","url":"https://www.easthants.gov.uk/sites/default/files/2026-03/Council%20tax%20per%20valuation%20band%202026-27.pdf"}]},{"id":"hinton-ampner-so24","name":"Hinton Ampner","village":"Hinton Ampner","town":"Winchester","county":"Hampshire","postcode":"SO24","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.08068,"lng":-1.16892},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Hinton Ampner is a Hampshire settlement in the SO24 area with longstanding parish and agricultural roots. It sits within a wider rural-commuter geography connected to nearby towns for day-to-day services. Current appeal is primarily village character, countryside access and practical road links across the county.","character":"Rural Hampshire settlement character with mixed housing, parish identity and open countryside setting.","amenities":["Local parish/community facilities in Hinton Ampner or adjoining villages.","Countryside footpaths, lanes and green-space recreation.","Wider shopping, healthcare and rail options in nearby towns."],"schools":[{"name":"Hinton Ampner area primary catchment school","phase":"Primary","type":"State","ofsted":null,"distance":"~1-5 miles","url":"https://www.hants.gov.uk/educationandlearning/findaschool"},{"name":"Winchester area secondary catchment school","phase":"Secondary","type":"State","ofsted":null,"distance":"~4-10 miles","url":"https://www.hants.gov.uk/educationandlearning/findaschool"}],"transport":{"commutes":[{"to":"Winchester","mode":"Drive","typical":"~15-35 min","notes":"Var